#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";abi=x86_64;serial=emulator-5554;timeout=30;while (($#));do case "$1" in --android-abi)abi="${2:?}";shift 2;;--serial)serial="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";apk="$ARCHPHENE_ROOT/prototypes/camera-capability-probe/out-$abi/archphene-camera-probe.apk";archphene_require_file "$apk";package=org.archphene.cameraprobe;archphene_adb_run install -r "$apk" >/dev/null;archphene_adb_run shell pm revoke "$package" android.permission.CAMERA >/dev/null 2>&1 || true;archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$package/org.archphene.bridge.CameraProbeActivity" >/dev/null;archphene_wait_ui_text 'While using the app' camera-permission "$timeout" || archphene_wait_ui_text Allow camera-permission "$timeout";ui="$ARCHPHENE_UI";if [[ "$ui" == *'While using the app'* ]];then archphene_tap_text "$ui" 'While using the app';else archphene_tap_text "$ui" Allow;fi;log="$(archphene_wait_log 'Camera capture completed|Camera broker' "$timeout" 'ArchpheneCapabilities AndroidRuntime *:S')";[[ "$log" != *'FATAL EXCEPTION'* ]] || archphene_die 'camera probe crashed';archphene_note "Android camera bridge passed on $serial ($abi): permission, broker, and capture completion verified."
